import request from '@/utils/request'

/**
 * 分页列表
 */
export function getShiftList(params) {
  return request({
    url: '/api/shift',
    method: 'get',
    params,
  })
}

/**
 * 详情
 */
export function getShift(id) {
  return request({
    url: `/api/shift/${id}`,
    method: 'get',
  })
}

/**
 * 创建
 */
export function createShift(data) {
  return request({
    url: '/api/shift',
    method: 'post',
    data,
  })
}

/**
 * 更新
 */
export function updateShift(id, data) {
  return request({
    url: `/api/shift/${id}`,
    method: 'put',
    data,
  })
}

/**
 * 删除
 */
export function deleteShift(id) {
  return request({
    url: `/api/shift/${id}`,
    method: 'delete',
  })
}
